module RefModule(
    input [31:0] d,
    input clk,
    input reset,
    input en,
    output reg [31:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
    begin
        if (reset)
            q <= 32'b0;
        else if (en)
            q <= d;
    end

endmodule
